const express = require('express');
const fs = require('fs');
const path = require('path');
const axios = require('axios');
const vm = require('vm');

const app = express();
app.use(express.json());

class PluginManager {
  constructor() {
    this.plugins = [];
    this.allowedPluginDir = path.resolve(process.env.PLUGIN_DIR || './plugins');
    this.pluginWhitelist = this.loadPluginWhitelist();
  }

  loadPluginWhitelist() {
    const whitelistPath = process.env.PLUGIN_WHITELIST || './plugin-whitelist.json';
    try {
      if (fs.existsSync(whitelistPath)) {
        const content = fs.readFileSync(whitelistPath, 'utf8');
        return JSON.parse(content);
      }
    } catch (error) {
      console.error('Error loading plugin whitelist:', error.message);
    }
    return { allowedPlugins: [] };
  }

  validatePluginPath(pluginPath) {
    const resolvedPath = path.resolve(pluginPath);
    const normalizedAllowedDir = path.normalize(this.allowedPluginDir);
    const normalizedPath = path.normalize(resolvedPath);
    
    if (!normalizedPath.startsWith(normalizedAllowedDir)) {
      throw new Error('Plugin path outside allowed directory');
    }
    
    if (!fs.existsSync(resolvedPath)) {
      throw new Error('Plugin file does not exist');
    }
    
    const stats = fs.statSync(resolvedPath);
    if (!stats.isFile()) {
      throw new Error('Plugin path is not a file');
    }
    
    return resolvedPath;
  }

  isPluginWhitelisted(pluginName) {
    return this.pluginWhitelist.allowedPlugins.includes(pluginName);
  }

  loadPluginFromFile(pluginPath, pluginName) {
    try {
      if (!this.isPluginWhitelisted(pluginName)) {
        throw new Error(`Plugin ${pluginName} is not whitelisted`);
      }

      const validatedPath = this.validatePluginPath(pluginPath);
      
      delete require.cache[require.resolve(validatedPath)];
      const plugin = require(validatedPath);
      
      if (typeof plugin.execute !== 'function') {
        throw new Error('Plugin must export an execute function');
      }
      
      this.validatePluginStructure(plugin);
      
      this.plugins.push({
        name: pluginName,
        plugin: plugin,
        priority: plugin.priority || 100
      });
      
      console.log(`Loaded plugin: ${pluginName}`);
    } catch (error) {
      console.error(`Failed to load plugin ${pluginName}:`, error.message);
      throw error;
    }
  }

  validatePluginStructure(plugin) {
    const allowedProperties = ['execute', 'name', 'priority', 'description'];
    const pluginProps = Object.keys(plugin);
    
    for (const prop of pluginProps) {
      if (!allowedProperties.includes(prop)) {
        throw new Error(`Plugin contains disallowed property: ${prop}`);
      }
    }
    
    if (plugin.execute.length > 3) {
      throw new Error('Plugin execute function has invalid signature');
    }
  }

  loadPluginsFromConfig() {
    const configPath = process.env.PLUGIN_CONFIG || './plugin-config.json';
    
    try {
      if (!fs.existsSync(configPath)) {
        console.log('No plugin configuration file found');
        return;
      }
      
      const configContent = fs.readFileSync(configPath, 'utf8');
      const config = JSON.parse(configContent);
      
      if (!config.plugins || !Array.isArray(config.plugins)) {
        throw new Error('Invalid plugin configuration format');
      }
      
      for (const pluginConfig of config.plugins) {
        if (!pluginConfig.name || !pluginConfig.path) {
          console.error('Invalid plugin configuration entry');
          continue;
        }
        
        const pluginPath = path.join(this.allowedPluginDir, pluginConfig.path);
        this.loadPluginFromFile(pluginPath, pluginConfig.name);
      }
    } catch (error) {
      console.error('Error loading plugins from config:', error.message);
    }
  }

  async executePlugins(context) {
    const sortedPlugins = this.plugins.sort((a, b) => a.priority - b.priority);
    
    for (const { name, plugin } of sortedPlugins) {
      try {
        const sandboxContext = this.createSandboxContext(context);
        await plugin.execute(sandboxContext.request, sandboxContext.response, sandboxContext.next);
        
        context.request = sandboxContext.request;
        context.response = sandboxContext.response;
        
        if (sandboxContext.shouldStop) {
          break;
        }
      } catch (error) {
        console.error(`Error executing plugin ${name}:`, error.message);
        throw error;
      }
    }
  }

  createSandboxContext(context) {
    return {
      request: {
        headers: { ...context.request.headers },
        body: context.request.body ? JSON.parse(JSON.stringify(context.request.body)) : undefined,
        query: { ...context.request.query },
        params: { ...context.request.params },
        method: context.request.method,
        url: context.request.url
      },
      response: {
        headers: { ...context.response.headers },
        body: context.response.body,
        statusCode: context.response.statusCode
      },
      shouldStop: false,
      next: function() {
        this.shouldStop = false;
      }
    };
  }
}

const pluginManager = new PluginManager();

pluginManager.loadPluginsFromConfig();

const rateLimitStore = new Map();

function rateLimit(req, res, next) {
  const ip = req.ip;
  const now = Date.now();
  const windowMs = 60000;
  const maxRequests = 100;
  
  if (!rateLimitStore.has(ip)) {
    rateLimitStore.set(ip, []);
  }
  
  const requests = rateLimitStore.get(ip).filter(time => now - time < windowMs);
  
  if (requests.length >= maxRequests) {
    return res.status(429).json({ error: 'Too many requests' });
  }
  
  requests.push(now);
  rateLimitStore.set(ip, requests);
  next();
}

app.use(rateLimit);

function validateTargetUrl(url) {
  try {
    const parsed = new URL(url);
    
    if (!['http:', 'https:'].includes(parsed.protocol)) {
      throw new Error('Invalid protocol');
    }
    
    const hostname = parsed.hostname.toLowerCase();
    const blockedHosts = ['localhost', '127.0.0.1', '0.0.0.0', '::1'];
    
    if (blockedHosts.includes(hostname)) {
      throw new Error('Access to internal hosts is blocked');
    }
    
    if (hostname.startsWith('192.168.') || hostname.startsWith('10.') || 
        hostname.startsWith('172.16.') || hostname.startsWith('169.254.')) {
      throw new Error('Access to private networks is blocked');
    }
    
    return parsed.href;
  } catch (error) {
    throw new Error('Invalid target URL');
  }
}

app.all('/gateway/*', async (req, res) => {
  try {
    const targetPath = req.params[0];
    const targetUrl = process.env.BACKEND_URL || 'http://backend-service:8080';
    const fullUrl = `${targetUrl}/${targetPath}`;
    
    validateTargetUrl(fullUrl);
    
    const context = {
      request: {
        headers: req.headers,
        body: req.body,
        query: req.query,
        params: req.params,
        method: req.method,
        url: req.url
      },
      response: {
        headers: {},
        body: null,
        statusCode: 200
      }
    };
    
    await pluginManager.executePlugins(context);
    
    const proxyHeaders = { ...context.request.headers };
    delete proxyHeaders.host;
    delete proxyHeaders['content-length'];
    
    const response = await axios({
      method: context.request.method,
      url: fullUrl,
      headers: proxyHeaders,
      data: context.request.body,
      params: context.request.query,
      validateStatus: () => true,
      maxRedirects: 5,
      timeout: 30000
    });
    
    context.response.body = response.data;
    context.response.statusCode = response.status;
    context.response.headers = response.headers;
    
    await pluginManager.executePlugins(context);
    
    Object.keys(context.response.headers).forEach(key => {
      res.setHeader(key, context.response.headers[key]);
    });
    
    res.status(context.response.statusCode).send(context.response.body);
    
  } catch (error) {
    console.error('Gateway error:', error.message);
    res.status(500).json({ error: 'Internal gateway error' });
  }
});

